const rootSite = $input.all()[0].json;

if (!rootSite || !rootSite.id) {
  throw new Error('Could not get root site — check Saara - Sharepoint credential');
}

const webUrl = rootSite.webUrl || '';
const match = webUrl.match(/https:\/\/([^.]+\.sharepoint\.com)/);
const tenantDomain = match ? match[1] : null;

if (!tenantDomain) {
  throw new Error(`Could not extract tenant domain from webUrl: ${webUrl}`);
}

const targetSiteName = $('Setup Config').item.json.SITE_NAME;

return [{
  json: {
    tenantDomain,
    targetSiteName,
    constructedSiteUrl: `https://${tenantDomain}/sites/${targetSiteName}`,
    rootSiteId: rootSite.id
  }
}];

const drives = $input.all()[0].json.value || [];
const targetLibraryName = $('Setup Config').item.json.LIBRARY_NAME;

let targetDrive = drives.find(drive =>
  drive.name && drive.name.toLowerCase() === targetLibraryName.toLowerCase()
);

if (!targetDrive) {
  const fallbacks = ['Documents', 'Shared Documents', 'Document Library'];
  targetDrive = drives.find(drive =>
    fallbacks.some(name =>
      drive.name && drive.name.toLowerCase().includes(name.toLowerCase())
    )
  );
}

if (!targetDrive) {
  throw new Error(`Library "${targetLibraryName}" not found. Available: ${drives.map(d => d.name).join(', ')}`);
}

return [{
  json: {
    driveId: targetDrive.id,
    driveName: targetDrive.name,
    siteId: $('Access Saara Site').item.json.id
  }
}];

// $input.all()              → processed_sharepoint_files rows from Supabase
// $('List SOP Files').all() → Graph API response ({ value: [...] })

const processedIds = new Set(
  $input.all()
    .map(item => item.json.file_id)
    .filter(Boolean)
);

const allItems = $('List SOP Files').all()[0]?.json?.value ?? [];

if (allItems.length === 0) {
  return [{ json: { hasNewFiles: false, count: 0 } }];
}

// Keep only MP4 files (skip folders and non-MP4)
const mp4Files = allItems.filter(item => {
  if (item.folder) return false;
  const byMime = item.file?.mimeType === 'video/mp4';
  const byExt  = typeof item.name === 'string' && item.name.toLowerCase().endsWith('.mp4');
  return byMime || byExt;
});

// Keep only files not yet in processed_sharepoint_files
const newFiles = mp4Files.filter(file => !processedIds.has(file.id));

if (newFiles.length === 0) {
  return [{ json: { hasNewFiles: false, count: 0 } }];
}

// Pass siteId/driveId through for the Download node URL
const siteId  = $('Find Documents Library').first().json.siteId;
const driveId = $('Find Documents Library').first().json.driveId;

return newFiles.map(file => ({
  json: {
    hasNewFiles:        true,
    sharepoint_file_id: file.id,
    file_name:          file.name,
    file_size_bytes:    file.size ?? 0,
    last_modified:      file.lastModifiedDateTime ?? null,
    download_url:       file['@microsoft.graph.downloadUrl'] ?? null,
    siteId,
    driveId
  }
}));

// Generate UUID without crypto module (n8n cloud blocks it)
function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const batchItem = $('Process One File At a Time').first().json;

const sopId    = uuid();
const fileName = batchItem.file_name || 'recording.mp4';
const fileSize = batchItem.file_size_bytes || 0;
const spFileId = batchItem.sharepoint_file_id;

// Clean filename for title
const cleanName = fileName
  .replace(/\.(mp4|mkv|avi|mov|webm|wmv)$/i, '')
  .replace(/[_-]/g, ' ')
  .trim();

const ext = fileName.split('.').pop().toLowerCase();
const mimeMap = {
  'mp4': 'video/mp4',
  'mkv': 'video/x-matroska',
  'avi': 'video/x-msvideo',
  'mov': 'video/quicktime',
  'webm': 'video/webm',
  'wmv': 'video/x-ms-wmv'
};
const mimeType = mimeMap[ext] || 'video/mp4';

const blobAccount   = $('Setup Config').first().json.AZURE_BLOB_ACCOUNT;
const blobContainer = $('Setup Config').first().json.AZURE_BLOB_CONTAINER;

return [{
  json: {
    sop_id:             sopId,
    file_name:          fileName,
    file_size_bytes:    fileSize,
    sharepoint_file_id: spFileId,
    mime_type:          mimeType,
    blob_url:           `https://${blobAccount}.blob.core.windows.net/${blobContainer}/${sopId}/original.${ext}`,
    title:              `${cleanName} — Knowledge Transfer`,
    meeting_date:       new Date().toISOString().split('T')[0]
  },
  binary: $input.first().binary
}];

